// // This module is designed to select one of four 5-bit input signals (d, c, b, a) based on a 2-bit select input (sel). The output (o) reflects the value of the selected input according to the state of sel, where sel = 00 outputs d, sel = 01 outputs c, sel = 10 outputs b, and sel = 11 outputs a.
module top_module(
	input [1:0] sel,
	input [4:0] a,
	input [4:0] b,
	input [4:0] c,
	input [4:0] d,
	output reg [4:0] o
    );always @(*) begin
	 case (sel)
	 2'b00: o = a;
	 2'b01: o = b;
	 2'b10: o = c;
	 2'b11: o = d;
	 endcase
	 end
endmodule
